    	break;
    }

  14. 【P76-78】Java大数计算 BigInteger（整数）和BigDecimal（浮点数）

        public class Test {
        public static void main(String[] args) {
            //计算1000!
            BigInteger ans = BigInteger.valueOf(1);
            for(int i=1;i<=1000;i++){
                BigInteger input = BigInteger.valueOf(i);
