#### SPFA

算法思路

**算法思想：**

我们用数组记录每个结点的最短路径估计值，用邻接表来存储图G。

我们采取的方法是动态逼近法：1.设立一个先进先出的队列用来保存待优化的结点。 2.优化时每次取出队首结点u，并且用u点当前的最短路径估计值对离开u点所指向的结点v进行松弛操作，如果v点的最短路径估计值有所调整，且v点不在当前的队列中，就将v点放入队尾。 3.这样不断从队列中取出结点来进行松弛操作，直至队列空为止。

期望的时间复杂度O(ke)， 其中k为所有顶点进队的平均次数，可以证明k一般小于等于2。（?）

        procedure Shortest-Path-Faster-Algorithm(G, s)
       for each vertex v ≠ s in V(G)
           d(v) := ∞
       d(s) := 0
       offer s into PQ //PQ是优先队列
       while PQ is not empty
           u := poll PQ
           for each edge (u, v) in E(G)
               if d(u) + w(u, v) < d(v) then
                   d(v) := d(u) + w(u, v)
                   if v is not in PQ then
                       offer v into PQ

        //bfs 万能啊
    int spfa_bfs(int s){
        queue <int> q;
        memset(d,0x3f,sizeof(d));
        d[s]=0;
        memset(c,0,sizeof(c));
        memset(vis,0,sizeof(vis));

        q.push(s);  vis[s]=1; c[s]=1;
        //顶点入队vis要做标记，另外要统计顶点的入队次数
        int OK=1;
        while(!q.empty())
        {
            int x;
            x=q.front(); q.pop();  vis[x]=0;
            //队头元素出队，并且消除标记
            for(int k=f[x]; k!=0; k=nnext[k]) //遍历顶点x的邻接表
            {
                int y=v[k];
                if( d[x]+w[k] < d[y])
                {
                    d[y]=d[x]+w[k];  //松弛
                    if(!vis[y])  //顶点y不在队内
                    {
                        vis[y]=1;    //标记
                        c[y]++;      //统计次数
                        q.push(y);   //入队
                        if(c[y]>NN)  //超过入队次数上限，说明有负环
                            return OK=0;
                    }
                }
            }
        }
        return OK;
    }

    //dfs处理负环更快，但是仅限于有限深度
    int spfa_dfs(int u)
    {
        vis[u]=1;
        for(int k=f[u]; k!=0; k=e[k].next)
        {
            int v=e[k].v,w=e[k].w;
            if( d[u]+w < d[v] )
            {
                d[v]=d[u]+w;
                if(!vis[v])
                {
                    if(spfa_dfs(v))
                        return 1;
                }
                else
                    return 1;
            }
        }
        vis[u]=0;
        return 0;
    }

