    4 8   
    1 2 2   
    1 3 6   
    1 4 4   
    2 3 3   
    3 1 7   
    3 4 1   
    4 1 5   
    4 3 12 
    */
    //传递闭包问题的修改版
    void floyd(){
        for(int k=0;k<n;k++){
            for(int i=0;i<n;i++){
                for(int j=0;j<n;j++){
                    dp[i][j]=dp[i][j]||(dp[i][k]&&dp[k][j]);
                }
            }
        }
    }

