     *     int val;
     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        vector<double> averageOfLevels(TreeNode* root) {
            vector<double> ans;
            queue<TreeNode*> que;
            que.push(root);
            while(!que.empty()){
                int SIZE = que.size();
                double avg = 0;
                for(int i=0;i<SIZE;i++){
                    TreeNode* p = que.front();
                    que.pop();
                    // if(p==NULL) continue; //非空二叉树
                    avg += p->val;
                    if(p->left!=NULL){
                        que.push(p->left);
                    }
                    if(p->right!=NULL){
                        que.push(p->right);
                    }
                }
                ans.push_back(avg/SIZE);
            }
            return ans;
        }
    };

