            if (root == NULL) return;
            dfs(root->left, prev, res);
            if (prev >= 0) res = min(res, root->val - prev);
            prev = root->val;
            dfs(root->right, prev, res);
        }
        int getMinimumDifference(TreeNode* root) {
            int prev = -1;
            int res = INT_MAX;
            dfs(root, prev, res);
            return res;
        }
