     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        int findTilt(TreeNode* root) {
            getSum(root);
            return tilt;
        }

        int getSum(TreeNode* root) {
            if(root==NULL)return 0;
            int L = getSum(root->left);
            int R = getSum(root->right);
            tilt += abs(L - R);
            return L + R + root->val;
        }

    private:
        int tilt = 0;
    };

