617.[合并二叉树](https://leetcode-cn.com/problems/merge-two-binary-trees/) ★★

**一开始没想到的是孩子为空的时候啥也不用做，直接连接即可。**

我们可以对这两棵树同时进行前序遍历，并将对应的节点进行合并。在遍历时，如果两棵树的当前节点均不为空，我们就将它们的值进行相加，并对它们的左孩子和右孩子进行递归合并；如果其中有一棵树为空，那么我们返回另一颗树作为结果；如果两棵树均为空，此时返回任意一棵树均可（因为都是空）。


    /**
     * Definition for a binary tree node.
     * struct TreeNode {
     *     int val;
     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        TreeNode* mergeTrees(TreeNode* t1, TreeNode* t2) {
            TreeNode* root = t1 ? t1 : t2;
            if(t1&&t2){
                t1->val += t2->val;
                t1->left = mergeTrees(t1->left,t2->left);
                t1->right = mergeTrees(t1->right,t2->right);
            }
            return root;
        }
    };

非递归的实现：如果t1和t2非空，则将其val求和并赋值给t1，然后考虑左右孩子，（以左孩为例）如果t1左孩子为空，则将t2的左孩子作为t1的左孩子，如果t1左孩子非空，则将结点入栈/队，两者皆空则无操作（上述，右孩子同理）；如果t1为空，则返回t2（无论t2是否为空，不影响结果），否则返回t1。


    /**
     * Definition for a binary tree node.
     * struct TreeNode {
     *     int val;
     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        TreeNode* mergeTrees(TreeNode* t1, TreeNode* t2) {
            //判断t1空的情况，while循环仅执行一次
            TreeNode* root = t1 ? t1 : t2;

            queue< pair<TreeNode*,TreeNode*> > que;
            que.push(make_pair(t1,t2));
            while(!que.empty()) {
                pair<TreeNode*,TreeNode*> hp = que.front();
                que.pop();
                TreeNode* p = hp.first;
                TreeNode* q = hp.second;
                //若t1为空，循环结束；或者p非空而q空，
                //该情况出现在树t1的左或右孩子非空而树t2与之对应的孩子为空
                if(p==NULL || q==NULL) continue;
                p->val += q->val;
                //分别判断左右孩子
                if(p->left==NULL) {
                    p->left = q->left;
                } else {
                    que.push(make_pair(p->left,q->left));
                }
                if(p->right==NULL) {
                    p->right = q->right;
                } else {
                    que.push(make_pair(p->right,q->right));
                }
            }
            return root;
        }
    };

637.[二叉树的层平均值](https://leetcode-cn.com/problems/average-of-levels-in-binary-tree/)


    /**
     * Definition for a binary tree node.
     * struct TreeNode {
     *     int val;
     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        vector<double> averageOfLevels(TreeNode* root) {
            vector<double> ans;
            queue<TreeNode*> que;
            que.push(root);
            while(!que.empty()){
                int SIZE = que.size();
                double avg = 0;
                for(int i=0;i<SIZE;i++){
                    TreeNode* p = que.front();
                    que.pop();
                    // if(p==NULL) continue; //非空二叉树
                    avg += p->val;
                    if(p->left!=NULL){
                        que.push(p->left);
                    }
                    if(p->right!=NULL){
                        que.push(p->right);
                    }
                }
                ans.push_back(avg/SIZE);
            }
            return ans;
        }
    };

