    class Solution {
    public:
        int rangeSumBST(TreeNode* root, int L, int R) {
            int sum = 0;
            if(root!=NULL) {
                if(root->val < L) {
                    sum = rangeSumBST(root->right, L, R);
                } else if(root->val > R) {
                    sum = rangeSumBST(root->left, L, R);
                } else {
                    sum = root->val + rangeSumBST(root->left, L, R) 
                            + rangeSumBST(root->right, L, R);
                }
            }
            return sum;
        }
    };

