            return (parx!=pary && dx==dy);
        }

        void dfs(TreeNode* root, int x, int y, int d,TreeNode* par) {
            if(root==NULL) return;
            if(root->val == x){
                parx = par;
                dx = d;
            }
            if(root->val == y) {
                pary = par;
                dy = d;
            }
            dfs(root->left, x, y, d+1, root);
            dfs(root->right, x, y, d+1, root);
        }
    private:
        TreeNode* parx = nullptr;
        TreeNode* pary = nullptr;
        int dx=0, dy = 0;
