    class Solution {
    public:
        bool isPalindrome(int x) {
            /* 判断特殊情况
             * 情况1:负数  情况2:末尾有0的整数,反转后前缀0没了,满足条件的只有0
             */
            if(x<0 || (x%10==0 && x!=0)){
                return false;
            }
            //为了防止溢出,反转一半的数字
            //int len = 0;这里不需要求出长度,数字对半分之后可以比较出大小
            int half = 0;
            while(x > half){
                int tmp = x%10;
                half = half*10 + tmp;
