    class Solution {//简单的堆栈应用
        public boolean isValid(String s) {
            //Stack<Character> stk = new Stack<>();
            Stack stk = new Stack();
            if(s.length()%2==1)
                return false;
            if(s.length()==0)
                return true;
            //stk.push(s.charAt(0));
            for(int i=0;i<s.length();i++){
                if(stk.empty()){
                    stk.push(s.charAt(i));
                    continue;
                }
                char c = (char)stk.peek();
                if(s.charAt(i)==')' && c=='(' || s.charAt(i)==']' && c=='[' ||s.charAt(i)=='}' && c=='{'){
                    stk.pop();
                }
                else 
                    stk.push(s.charAt(i));
            }
            if(stk.empty())
                return true;
            return false;
        }
    }


