            string ans = ""; //感觉可以直接在a b上操作
            int len_a = a.length()-1;
            int len_b = b.length()-1;
            bool carry = false;
            while(len_a >=0 && len_b>=0){
                if(a[len_a]=='1' && b[len_b]=='1'){//1+1
                    ans = carry ? ("1" + ans) : ("0" + ans);
                    carry = true;
                }else if(a[len_a]=='0' && b[len_b]=='0'){//0+0
                    ans = carry ? ("1" + ans) : ("0" + ans);
                    carry = false;
                }else{//1+0的11情况
                    ans = carry ? ("0" + ans) : ("1" + ans);
                    //carry do not change.
                }
                len_a --;
                len_b --;
            }
            while(len_a >=0){
                if(a[len_a]=='0'){
                    ans = carry ? ("1" + ans) : ("0" + ans);
                    carry = false;
                }
                else {
                    ans = carry ? ("0" + ans) : ("1" + ans);
                    //carry do not change.
                }
                len_a --;
            }
            while(len_b >=0){
                if(b[len_b]=='0'){
                    ans = carry ? ("1" + ans) : ("0" + ans);
                    carry = false;
                }
                else {
                    ans = carry ? ("0" + ans) : ("1" + ans);
                    //carry do not change.
                }
                len_b --;
            }
            ans = carry ? ("1" + ans) : ans ;
            return ans;
        }
