    '''
    精妙的位运算方法
    A  B  ^  &  +
    0  0  0  0  0+0=00
    0  1  1  0  0+1=01
    1  0  1  0  1+0=01
    1  1  0  1  1+1=10
    统一先计算^这样没有进位，然后统一把进位求出来，加进去。 这样可能还会有进位，所以就继续循环，直到没有进位。
    '''
     class Solution:
        def addBinary(self, a, b) -> str:
            x, y = int(a, 2), int(b, 2)
            while y:
                answer = x ^ y
                carry = (x & y) << 1
                x, y = answer, carry
            return bin(x)[2:]

