     */
    class Solution { 
    public:
        bool isSameTree(TreeNode* p, TreeNode* q) {
            if(p==NULL && q==NULL){
                return true;
            }
            if((p!=NULL&&q==NULL) || (p==NULL&&q!=NULL) || (p->val!=q->val)){
                return false;
            }
