            bool flag_leaf = false;
            while(!que.empty()){
                min_depth ++;
                int size = que.size();
                for(int i=0;i<size;i++){
                    TreeNode* p = que.front();
                    que.pop();
                    if(p->left==NULL && p->right==NULL){
