            int scolor = image[sr][sc];
            while(!que.empty()){
                pair<int,int> pos = que.front();
                int r = pos.first;
                int c = pos.second;
                que.pop();
                if((0<=r && r<image.size()) && (0<=c && c<image[0].size()) && !visited[r][c]){
                    visited[r][c] = true;
                    if(image[r][c]==scolor){
