    //C++版,默认flag为true,去判断括号不匹配的情况
    //情况1:当前括号是右括号但是与栈顶的括号不匹配
    //情况2:当前括号是右括号但是栈空
    //情况3:括号串扫描结束，但栈中有多余的括号(奇数情况)
    class Solution {
    public:
        bool isValid(string s) {
            stack<char> st;
            bool flag = true;

            if(s.length()==0){
                return true;
            }

            for(int i=0;i<s.length();i++){
                if(s[i]=='(' || s[i]=='[' ||s[i]=='{'){
                    st.push(s[i]);
                }
                else {
                    if(!st.empty()){
                        char c = st.top();
                        st.pop();
                        if((s[i]==')'&&c=='(') || (s[i]==']'&&c=='[') || (s[i]=='}'&&c=='{')){
                            continue;
                        }
                        else {
                            flag = false;
                            break;
                        }
                    }
                    else {
                        flag = false;
                        break;
                    }
                }
            }

            if(!st.empty()){
                flag = false;
            }  

            return flag;
        }
    };

