    class Solution {
    public:
        int removeDuplicates(vector<int>& nums) {
            if(nums.size() == 0)
                return 0;
            //双指针(游标)法
            int end = 0; //存储新数组的尾部
            // int cur = 0; //当前遍历到的数字
            for(int cur=0;cur<nums.size();cur++){
                if(nums[cur]!=nums[end]){
                    end ++;
                    nums[end] = nums[cur];
                }
            }

            return end+1;
        }
    };

