    class Solution {//本质上是一个二分查找的题目
    public:
        int searchInsert(vector<int>& nums, int target) {
            int l = 0;
            int r = nums.size();
            //使用[l,r)的二分写法，最后返回首个大于等于target的值的位置
            while(l < r){//区间[l,r)非空
                int mid = l + (r - l)/2;
                if(nums[mid] >= target){
                    r = mid;
                } else {
                    l = mid + 1;
                }
            }
            return l;
        }
    };

