                }
                else {
                    ans = carry ? ("0" + ans) : ("1" + ans);
                    //carry do not change.
                }
                len_a --;
            }
            while(len_b >=0){
                if(b[len_b]=='0'){
                    ans = carry ? ("1" + ans) : ("0" + ans);
                    carry = false;
                }
                else {
                    ans = carry ? ("0" + ans) : ("1" + ans);
                    //carry do not change.
                }
                len_b --;
            }
            ans = carry ? ("1" + ans) : ans ;
            return ans;
        }
    };


