    /**
     * Definition for singly-linked list.
     * struct ListNode {
     *     int val;
     *     ListNode *next;
     *     ListNode(int x) : val(x), next(NULL) {}
     * };
     */
    class Solution {
    public:
        ListNode* deleteDuplicates(ListNode* head) {
            if(head==nullptr){
                return head;
            }
            ListNode* p = head; //慢指针
            ListNode* q = head->next; //快指针
            while(p!=nullptr && q!=nullptr){
                if(p->val == q->val){
                    p->next = q->next;
                    ListNode* del = q;
                    q = q->next;
                    delete del;
                }else{
                    p = p->next;
                    q = q->next;
                }
            }
            return head;
        }
    };


