     * };
     */
    class Solution { 
    public:
        bool isSameTree(TreeNode* p, TreeNode* q) {
            if(p==NULL && q==NULL){
                return true;
            }
            if((p!=NULL&&q==NULL) || (p==NULL&&q!=NULL) || (p->val!=q->val)){
                return false;
            }
            //递归地判断左右子树
            return isSameTree(p->left, q->left)&&isSameTree(p->right, q->right);

        }
    };


    /**
     * Definition for a binary tree node.
     * struct TreeNode {
     *     int val;
     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        int checkNode(TreeNode *p, TreeNode* q){
            if(p==NULL && q==NULL){
                return 1;
            }
            if((p!=NULL&&q==NULL) || (p==NULL&&q!=NULL) || (p->val!=q->val)){
                return 2;
            }
            return 3;
        }
        bool isSameTree(TreeNode* p, TreeNode* q) {
            queue<TreeNode*> que;
            que.push(p);
            que.push(q);//可以只用一个队列来存储两个结点
            //BFS
            while(!que.empty()){
                TreeNode* r = que.front();//由于只使用了一个队列，需要注意存取顺序对应
                que.pop();
                TreeNode* s = que.front();
                que.pop();
                switch(checkNode(r,s)){
                    case 1:continue;
                    case 2:return false;
                    case 3:
                        que.push(r->left);
                        que.push(s->left);
                        que.push(r->right);
                        que.push(s->right);
                    default:break;
                }
            }
            return true;
        }
    };

