    class Solution {
    public:
        int maxDepth(TreeNode* root) {
            if(root==NULL)
                return 0;
            int depth = 0;
            queue<TreeNode*> que;
            que.push(root);
            while(!que.empty()){
                depth ++; //能进入循环说明当前队列中保存了新的一层
                int size = que.size();
                for(int i=0;i<size;i++){
                    TreeNode* p = que.front();
                    que.pop();
                    if(p->left!=NULL){
                        que.push(p->left);
                    }
                    if(p->right!=NULL){
                        que.push(p->right);
                    }
                }
            }
            return depth; 
        }
    };

