    /**
     * Definition for a binary tree node.
     * struct TreeNode {
     *     int val;
     *     TreeNode *left;
     *     TreeNode *right;
     *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
     * };
     */
    class Solution {
    public:
        vector<vector<int>> levelOrderBottom(TreeNode* root) {
            vector< vector<int> > ans;
            if(root!=NULL){
                queue<TreeNode*> que;
                que.push(root);
                while(!que.empty()){
                    int size = que.size();
                    vector<int> tmp;
                    for(int i=0;i<size;i++){
                        TreeNode* p = que.front();
                        que.pop();
                        tmp.push_back(p->val);
                        if(p->left!=NULL){
                            que.push(p->left);
                        }
                        if(p->right!=NULL){
                            que.push(p->right);
                        }
                    }
                    ans.push_back(tmp);
                }
                reverse(ans.begin(),ans.end());
            }     
            return ans;
        }
    };

