        Node(int _val, vector<Node*> _children) {
            val = _val;
            children = _children;
        }
    };
    */

    class Solution {
    public:
        int maxDepth(Node* root) {
            if(root==NULL){
                return 0;
            }
            int size = root->children.size();
            if(size==0){ //没有孩子结点，说明当前root是叶子结点，返回深度1
                return 1;
            }
            int max_depth = -1;
            for(int i=0;i<size;i++){
                max_depth = max(max_depth, maxDepth(root->children[i]));
            }
            return max_depth + 1;
        }
    };

