    bool dfs(vector<vector<int>> &grid, int x, int y, const int n, const int m) {
      if (x < 0 || x >= n || y < 0 || y >= m) {
        return false;
      }
      if (grid[x][y] == 1) return true;
      grid[x][y] = 1;
      bool flag = true;
      for (const auto &dir : dirs) {
        // 这行代码被优化了，别用，“或”逻辑前面为1，“与”逻辑前面为0就会发生短路,dfs不会继续进行
